        const mcpTool: Record<string, unknown> = {
          type: "mcp",
          server_label: mcp.server_label,
          server_url: mcp.server_url,
        };
        if (mcp.headers) mcpTool.headers = mcp.headers;
        if (mcp.allowed_tools) mcpTool.allowed_tools = mcp.allowed_tools;
        toolDefs.push(mcpTool);
      }
    }

    const toolsByName = new Map(tools?.map((t) => [t.name, t]));

    let lastTextResponse = "";

    // eslint-disable-next-line no-constant-condition
    while (true) {
      const body: Record<string, unknown> = {
        model: this.model,
        max_tokens: 4096,
        messages: anthropicMessages,
      };

      if (systemPrompt) {
        body.system = systemPrompt;
      }

      if (toolDefs && toolDefs.length > 0) {
        body.tools = toolDefs;
      }

      const headers: Record<string, string> = {
        "Content-Type": "application/json",
        "x-api-key": this.apiKey,
        "anthropic-version": "2023-06-01",
      };

      if (mcpServers?.length) {
        headers["anthropic-beta"] = "mcp-client-2025-04-04";
      }

      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers,
        body: JSON.stringify(body),
      });

      if (!response.ok) {
        const text = await response.text();
        throw new Error(`Anthropic API error ${response.status}: ${text}`);
      }

      const data = await response.json();

      const textBlock = data.content?.find(
        (block: { type: string }) => block.type === "text",
      );
      if (textBlock) {
        lastTextResponse = textBlock.text;
      }

      // MCP server-side tools hit iteration limit — re-send to continue
      if (data.stop_reason === "pause_turn") {
        anthropicMessages.push({ role: "assistant", content: data.content });
        continue;
      }

      if (data.stop_reason !== "tool_use") {
        if (!lastTextResponse) {
          throw new Error("No text content in Anthropic response");
        }
        return lastTextResponse;
      }

      // Handle client-side tool calls
      const toolUseBlocks = data.content.filter(
        (block: { type: string }) => block.type === "tool_use",
      );

      anthropicMessages.push({ role: "assistant", content: data.content });

      const toolResults: AnthropicContentBlock[] = [];
      for (const toolUse of toolUseBlocks) {
        const tool = toolsByName.get(toolUse.name);
        if (!tool) {
          toolResults.push({
            type: "tool_result",
            tool_use_id: toolUse.id,
            content: `Error: unknown tool "${toolUse.name}"`,
          });
          continue;
        }
        try {
          const result = await tool.execute(toolUse.input);
          toolResults.push({
            type: "tool_result",
            tool_use_id: toolUse.id,
            content: result,
          });
        } catch (err) {
          toolResults.push({
            type: "tool_result",
            tool_use_id: toolUse.id,
            content: `Error: ${err instanceof Error ? err.message : String(err)}`,
          });
        }
      }

      anthropicMessages.push({ role: "user", content: toolResults });
    }
  }
}

import type { Message } from "../types";
import type { LLMProvider, ProviderConfig } from "./types";

export class OpenAIProvider implements LLMProvider {
  private apiKey: string;
  private model: string;

  constructor(config: ProviderConfig) {
    this.apiKey = config.apiKey;
    this.model = config.model || "gpt-4o";
  }

  async chat(messages: Message[], systemPrompt?: string): Promise<string> {
    const openaiMessages: Array<{ role: string; content: string }> = [];

    if (systemPrompt) {
      openaiMessages.push({ role: "system", content: systemPrompt });
    }

    for (const m of messages) {
      if (m.role === "context") {
        openaiMessages.push({ role: "user", content: `[Context]: ${m.content}` });
      } else if (m.role === "system") {
        openaiMessages.push({ role: "user", content: m.content });
      } else {
        openaiMessages.push({ role: m.role, content: m.content });
      }
    }

    const response = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${this.apiKey}`,
      },
      body: JSON.stringify({
        model: this.model,
        messages: openaiMessages,
        max_tokens: 4096,
      }),
    });

    if (!response.ok) {
      const text = await response.text();
      throw new Error(`OpenAI API error ${response.status}: ${text}`);
    }

    const data = await response.json();
    const choice = data.choices?.[0];
    if (!choice?.message?.content) {
      throw new Error("No content in OpenAI response");
    }
    return choice.message.content;
  }
}

import type { Message } from "../types";
import type { LLMProvider, ProviderConfig } from "./types";

export class DifyProvider implements LLMProvider {
  private apiKey: string;
  private baseUrl: string;

  constructor(config: ProviderConfig) {
    this.apiKey = config.apiKey;
    if (!config.baseUrl) {
      throw new Error("baseUrl is required for the Dify provider");
    }
    this.baseUrl = config.baseUrl.replace(/\/+$/, "");
  }

  async chat(messages: Message[], systemPrompt?: string): Promise<string> {
    const query = this.buildQuery(messages, systemPrompt);

    const response = await fetch(`${this.baseUrl}/v1/chat-messages`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${this.apiKey}`,
      },
      body: JSON.stringify({
        inputs: {},
        query,
        response_mode: "blocking",
        user: "explain-user",
      }),
    });

    if (!response.ok) {
      const text = await response.text();
      throw new Error(`Dify API error ${response.status}: ${text}`);
    }

    const data = await response.json();
    if (!data.answer) {
      throw new Error("No answer in Dify response");
    }
    return data.answer;
  }

  private buildQuery(messages: Message[], systemPrompt?: string): string {
    const parts: string[] = [];

    if (systemPrompt) {
      parts.push(`[System]: ${systemPrompt}`);
    }

    for (const m of messages) {
      if (m.role === "context") {
        parts.push(`[Context]: ${m.content}`);
      } else if (m.role === "system") {
        parts.push(`[System]: ${m.content}`);
      } else if (m.role === "assistant") {
        parts.push(`[Assistant]: ${m.content}`);
      } else {
        parts.push(m.content);
      }
    }

    return parts.join("\n\n");
  }
}

