package explain

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
)

const (
	anthropicDefaultModel = "claude-sonnet-4-20250514"
	anthropicAPIURL       = "https://api.anthropic.com/v1/messages"
	anthropicMaxTokens    = 4096
	anthropicMaxToolLoops = 10
)

// AnthropicConfig configures the Anthropic provider.
type AnthropicConfig struct {
	APIKey     string
	Model      string
	Tools      []Tool
	McpServers []McpServer
	HTTPClient HTTPClient
}

type anthropicProvider struct {
	apiKey     string
	model      string
	tools      []Tool
	mcpServers []McpServer
	httpClient HTTPClient
}

// NewAnthropicProvider returns a Provider backed by the Anthropic Messages API.
func NewAnthropicProvider(cfg AnthropicConfig) Provider {
	model := cfg.Model
	if model == "" {
		model = anthropicDefaultModel
	}
	client := cfg.HTTPClient
	if client == nil {
		client = http.DefaultClient
	}
	return &anthropicProvider{
		apiKey:     cfg.APIKey,
		model:      model,
		tools:      cfg.Tools,
		mcpServers: cfg.McpServers,
		httpClient: client,
	}
}

func (p *anthropicProvider) Complete(ctx context.Context, messages []Message) (string, error) {
	anthMsgs := make([]map[string]any, 0, len(messages))
	var systemParts []string

	for _, m := range messages {
		switch m.Role {
		case RoleSystem:
			systemParts = append(systemParts, m.Content)
		case RoleContext:
			anthMsgs = append(anthMsgs, map[string]any{
				"role":    "user",
				"content": "[Context]: " + m.Content,
			})
		default:
			anthMsgs = append(anthMsgs, map[string]any{
				"role":    string(m.Role),
				"content": m.Content,
			})
		}
	}

	var toolDefs []map[string]any
	for _, t := range p.tools {
		toolDefs = append(toolDefs, map[string]any{
			"name":         t.Name,
			"description":  t.Description,
			"input_schema": json.RawMessage(t.InputSchema),
		})
	}
	for _, mcp := range p.mcpServers {
		entry := map[string]any{
			"type":         "mcp",
			"server_label": mcp.ServerLabel,
			"server_url":   mcp.ServerURL,
		}
		if len(mcp.Headers) > 0 {
			entry["headers"] = mcp.Headers
		}
		if len(mcp.AllowedTools) > 0 {
			entry["allowed_tools"] = mcp.AllowedTools
		}
		toolDefs = append(toolDefs, entry)
	}

	toolsByName := make(map[string]*Tool, len(p.tools))
	for i := range p.tools {
		toolsByName[p.tools[i].Name] = &p.tools[i]
	}

	var lastTextResponse string

	for loop := 0; loop < anthropicMaxToolLoops; loop++ {
		body := map[string]any{
			"model":      p.model,
			"max_tokens": anthropicMaxTokens,
			"messages":   anthMsgs,
		}
		if len(systemParts) > 0 {
			system := ""
			for i, s := range systemParts {
				if i > 0 {
					system += "\n\n"
				}
				system += s
			}
			body["system"] = system
		}
		if len(toolDefs) > 0 {
			body["tools"] = toolDefs
		}

		headers := map[string]string{
			"Content-Type":     "application/json",
			"x-api-key":        p.apiKey,
			"anthropic-version": "2023-06-01",
		}
		if len(p.mcpServers) > 0 {
			headers["anthropic-beta"] = "mcp-client-2025-04-04"
		}

		data, err := p.doRequest(ctx, headers, body)
		if err != nil {
			return "", err
		}

		// Extract text from content blocks
		if content, ok := data["content"].([]any); ok {
			for _, block := range content {
				bm, ok := block.(map[string]any)
				if !ok {
					continue
				}
				if bm["type"] == "text" {
					if text, ok := bm["text"].(string); ok {
						lastTextResponse = text
					}
				}
			}
		}

		stopReason, _ := data["stop_reason"].(string)

		// MCP pause — re-send with assistant content to continue
		if stopReason == "pause_turn" {
			anthMsgs = append(anthMsgs, map[string]any{
				"role":    "assistant",
				"content": data["content"],
			})
			continue
		}

		if stopReason != "tool_use" {
			if lastTextResponse == "" {
				return "", fmt.Errorf("no text content in Anthropic response")
			}
			return lastTextResponse, nil
		}

		// Handle tool calls
		content, _ := data["content"].([]any)
		anthMsgs = append(anthMsgs, map[string]any{
			"role":    "assistant",
			"content": content,
		})

		var toolResults []map[string]any
		for _, block := range content {
			bm, ok := block.(map[string]any)
			if !ok {
				continue
			}
			if bm["type"] != "tool_use" {
				continue
			}
			toolID, _ := bm["id"].(string)
			toolName, _ := bm["name"].(string)

			tool, exists := toolsByName[toolName]
			if !exists {
				toolResults = append(toolResults, map[string]any{
					"type":        "tool_result",
					"tool_use_id": toolID,
					"content":     fmt.Sprintf("Error: unknown tool %q", toolName),
				})
				continue
			}

			inputBytes, err := json.Marshal(bm["input"])
			if err != nil {
				toolResults = append(toolResults, map[string]any{
					"type":        "tool_result",
					"tool_use_id": toolID,
					"content":     fmt.Sprintf("Error: %s", err),
				})
				continue
			}

			result, err := tool.Execute(inputBytes)
			if err != nil {
				toolResults = append(toolResults, map[string]any{
					"type":        "tool_result",
					"tool_use_id": toolID,
					"content":     fmt.Sprintf("Error: %s", err),
				})
				continue
			}

			toolResults = append(toolResults, map[string]any{
				"type":        "tool_result",
				"tool_use_id": toolID,
				"content":     result,
			})
		}

		anthMsgs = append(anthMsgs, map[string]any{
			"role":    "user",
			"content": toolResults,
		})
	}

	if lastTextResponse != "" {
		return lastTextResponse, nil
	}
	return "", fmt.Errorf("anthropic tool loop exceeded maximum iterations")
}

func (p *anthropicProvider) doRequest(ctx context.Context, headers map[string]string, body map[string]any) (map[string]any, error) {
	bodyBytes, err := json.Marshal(body)
	if err != nil {
		return nil, fmt.Errorf("marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, anthropicAPIURL, bytes.NewReader(bodyBytes))
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}
	for k, v := range headers {
		req.Header.Set(k, v)
	}

	resp, err := p.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("anthropic request: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("Anthropic API error %d: %s", resp.StatusCode, string(respBody))
	}

	var data map[string]any
	if err := json.Unmarshal(respBody, &data); err != nil {
		return nil, fmt.Errorf("decode response: %w", err)
	}
	return data, nil
}

