	"net/http"
)

const (
	openaiDefaultModel = "gpt-4o"
	openaiAPIURL       = "https://api.openai.com/v1/chat/completions"
	openaiMaxTokens    = 4096
)

// OpenAIConfig configures the OpenAI provider.
type OpenAIConfig struct {
	APIKey     string
	Model      string
	HTTPClient HTTPClient
}

type openaiProvider struct {
	apiKey     string
	model      string
	httpClient HTTPClient
}

// NewOpenAIProvider returns a Provider backed by the OpenAI Chat Completions API.
func NewOpenAIProvider(cfg OpenAIConfig) Provider {
	model := cfg.Model
	if model == "" {
		model = openaiDefaultModel
	}
	client := cfg.HTTPClient
	if client == nil {
		client = http.DefaultClient
	}
	return &openaiProvider{
		apiKey:     cfg.APIKey,
		model:      model,
		httpClient: client,
	}
}

func (p *openaiProvider) Complete(ctx context.Context, messages []Message) (string, error) {
	oaiMsgs := make([]map[string]string, 0, len(messages)+1)

	// Collect system messages into a single system message.
	var systemContent string
	for _, m := range messages {
		if m.Role == RoleSystem {
			if systemContent != "" {
				systemContent += "\n\n"
			}
			systemContent += m.Content
		}
	}
	if systemContent != "" {
		oaiMsgs = append(oaiMsgs, map[string]string{
			"role":    "system",
			"content": systemContent,
		})
	}

	for _, m := range messages {
		switch m.Role {
		case RoleSystem:
			continue // already handled above
		case RoleContext:
			oaiMsgs = append(oaiMsgs, map[string]string{
				"role":    "user",
				"content": "[Context]: " + m.Content,
			})
		default:
			oaiMsgs = append(oaiMsgs, map[string]string{
				"role":    string(m.Role),
				"content": m.Content,
			})
		}
	}

	body := map[string]any{
		"model":      p.model,
		"messages":   oaiMsgs,
		"max_tokens": openaiMaxTokens,
	}

	bodyBytes, err := json.Marshal(body)
	if err != nil {
		return "", fmt.Errorf("marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, openaiAPIURL, bytes.NewReader(bodyBytes))
	if err != nil {
		return "", fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+p.apiKey)

	resp, err := p.httpClient.Do(req)
	if err != nil {
		return "", fmt.Errorf("openai request: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", fmt.Errorf("read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("OpenAI API error %d: %s", resp.StatusCode, string(respBody))
	}

	var data struct {
		Choices []struct {
			Message struct {
				Content string `json:"content"`
			} `json:"message"`
		} `json:"choices"`
	}
	if err := json.Unmarshal(respBody, &data); err != nil {
		return "", fmt.Errorf("decode response: %w", err)
	}

	if len(data.Choices) == 0 || data.Choices[0].Message.Content == "" {
		return "", fmt.Errorf("no content in OpenAI response")
	}
	return data.Choices[0].Message.Content, nil
}

