package explain

import (
	"context"
	"encoding/json"
	"net/http"
)

// Config holds the configuration for creating an AssistantHandler.
type Config struct {
	Provider    Provider
	Middlewares []Middleware
	BearerToken string // optional; if set, requests must carry this token
}

// NewHandler creates an http.Handler that processes assistant chat requests.
func NewHandler(cfg Config) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			writeError(w, http.StatusMethodNotAllowed, "method not allowed")
			return
		}

		if cfg.BearerToken != "" {
			auth := r.Header.Get("Authorization")
			if len(auth) < 8 || auth[:7] != "Bearer " || auth[7:] != cfg.BearerToken {
				writeError(w, http.StatusUnauthorized, "unauthorized")
				return
			}
		}

		var req Request
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			writeError(w, http.StatusBadRequest, "invalid request body")
			return
		}
		if len(req.Messages) == 0 {
			writeError(w, http.StatusBadRequest, "messages array is required and must not be empty")
			return
		}

		fn := func(ctx interface{ Value(any) any }, msgs []Message) (string, error) {
			return cfg.Provider.Complete(r.Context(), msgs)
		}
		// Build middleware chain from last to first.
		for i := len(cfg.Middlewares) - 1; i >= 0; i-- {
			mw := cfg.Middlewares[i]
			innerFn := fn
			fn = func(ctx interface{ Value(any) any }, msgs []Message) (string, error) {
				return mw(r.Context(), msgs, innerFn)
			}
		}

		reply, err := fn(r.Context(), req.Messages)
		if err != nil {
			writeError(w, http.StatusBadGateway, err.Error())
			return
		}

		writeJSON(w, http.StatusOK, Response{Reply: reply})
	})
}

func writeError(w http.ResponseWriter, code int, msg string) {
	writeJSON(w, code, ErrorResponse{Error: msg})
}

func writeJSON(w http.ResponseWriter, code int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(code)
	json.NewEncoder(w).Encode(v) //nolint:errcheck
}

